void NativeIndexdFfi::registerModule(
    jsi::Runtime &rt, std::shared_ptr<react::CallInvoker> callInvoker) {
  auto invoker =
      std::make_shared<uniffi_runtime::UniffiCallInvoker>(callInvoker);
  auto tm = std::make_shared<NativeIndexdFfi>(rt, invoker);
  auto obj = rt.global().createFromHostObject(rt, tm);
  rt.global().setProperty(rt, "NativeIndexdFfi", obj);
}

void NativeIndexdFfi::unregisterModule(jsi::Runtime &rt) {
  uniffi::indexd_ffi::registry::clearRegistry();
}

jsi::Value NativeIndexdFfi::get(jsi::Runtime &rt, const jsi::PropNameID &name) {
  try {
    return jsi::Value(rt, props.at(name.utf8(rt)));
  } catch (std::out_of_range &e) {
    return jsi::Value::undefined();
  }
}

std::vector<jsi::PropNameID>
NativeIndexdFfi::getPropertyNames(jsi::Runtime &rt) {
  std::vector<jsi::PropNameID> rval;
  for (auto &[key, value] : props) {
    rval.push_back(jsi::PropNameID::forUtf8(rt, key));
  }
  return rval;
}

void NativeIndexdFfi::set(jsi::Runtime &rt, const jsi::PropNameID &name,
                          const jsi::Value &value) {
  props.insert_or_assign(name.utf8(rt), &value);
}

NativeIndexdFfi::~NativeIndexdFfi() {
  // Cleanup for callback function RustFutureContinuationCallback
  uniffi::indexd_ffi::cb::rustfuturecontinuationcallback::cleanup();
  // Cleanup for "free" callback function CallbackInterfaceFree
  uniffi::indexd_ffi::st::foreignfuture::foreignfuture::free::cleanup();
  uniffi::indexd_ffi::st::vtablecallbackinterfacelogger::
      vtablecallbackinterfacelogger::free::cleanup();
  uniffi::indexd_ffi::st::vtablecallbackinterfaceuploadprogresscallback::
      vtablecallbackinterfaceuploadprogresscallback::free::cleanup();
  // Cleanup for callback function CallbackInterfaceLoggerMethod0
  uniffi::indexd_ffi::cb::callbackinterfaceloggermethod0::cleanup();
  // Cleanup for callback function CallbackInterfaceLoggerMethod1
  uniffi::indexd_ffi::cb::callbackinterfaceloggermethod1::cleanup();
  // Cleanup for callback function CallbackInterfaceLoggerMethod2
  uniffi::indexd_ffi::cb::callbackinterfaceloggermethod2::cleanup();
  // Cleanup for callback function CallbackInterfaceLoggerMethod3
  uniffi::indexd_ffi::cb::callbackinterfaceloggermethod3::cleanup();
  // Cleanup for callback function
  // CallbackInterfaceUploadProgressCallbackMethod0
  uniffi::indexd_ffi::cb::callbackinterfaceuploadprogresscallbackmethod0::
      cleanup();
}

